CREATE TABLE `global_reviewer_comments` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `global_submission_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `author_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `author_role` enum('HUNTER','MENTOR','QUALITY_CHECKER','SUPER_ADMIN') COLLATE utf8mb4_unicode_ci NOT NULL,
  `anchor` json DEFAULT NULL,
  `body` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `resolved_at` datetime(3) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `grc_global_submission_id_idx` (`global_submission_id`),
  CONSTRAINT `grc_global_submission_id_fkey` FOREIGN KEY (`global_submission_id`) REFERENCES `global_submissions` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

