CREATE TABLE `global_submissions` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `report_draft_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `revision_number` int NOT NULL,
  `payload` json NOT NULL,
  `submitted_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `submitted_by` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reviewer_role` enum('HUNTER','MENTOR','QUALITY_CHECKER','SUPER_ADMIN') COLLATE utf8mb4_unicode_ci NOT NULL,
  `decision` enum('PENDING','APPROVE','REQUEST_CHANGES','ENDORSE') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING',
  `decided_at` datetime(3) DEFAULT NULL,
  `decided_by` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `gs_draft_rev_role_uq` (`report_draft_id`,`revision_number`,`reviewer_role`),
  KEY `gs_report_draft_id_idx` (`report_draft_id`),
  KEY `gs_reviewer_decision_idx` (`reviewer_role`,`decision`),
  CONSTRAINT `gs_report_draft_id_fkey` FOREIGN KEY (`report_draft_id`) REFERENCES `report_drafts` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `global_submissions` (`id`, `report_draft_id`, `revision_number`, `payload`, `submitted_at`, `submitted_by`, `reviewer_role`, `decision`, `decided_at`, `decided_by`) VALUES
('bbbbbbbb-0401-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	1,	'{\"meta\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"cve\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"impact\\\\\\\": \\\\\\\"Lecture de fichier arbitraire et fuite de données (flag CTF)\\\\\\\", \\\\\\\"bugType\\\\\\\": \\\\\\\"CWE-22\\\\\\\", \\\\\\\"ipsUsed\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"payload\\\\\\\": \\\\\\\"public/.\\\\\\\\n./super_secret.txt\\\\\\\", \\\\\\\"endpoint\\\\\\\": \\\\\\\"GET /?action=generate&filename=...&expires=...&signature=...\\\\\\\", \\\\\\\"scopeSlug\\\\\\\": \\\\\\\"dojo-50\\\\\\\", \\\\\\\"reportTitle\\\\\\\": \\\\\\\"Rapport challenge n°50 Dojo YesWeHack\\\\\\\", \\\\\\\"vulnerablePartName\\\\\\\": \\\\\\\"filename\\\\\\\", \\\\\\\"technicalEnvironment\\\\\\\": \\\\\\\"Dojo YesWeHack — PHP, stockage signé\\\\\\\", \\\\\\\"applicationFingerprint\\\\\\\": \\\\\\\"PHP — Bucket Vault\\\\\\\", \\\\\\\"vulnerablePartCategory\\\\\\\": \\\\\\\"GET_PARAMETER\\\\\\\"}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"final\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": []}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"risks\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"risk-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Le risque principal est la **lecture de fichier arbitraire** hors du répertoire autorisé, entraînant une fuite de données sensibles (ici le flag). Un attaquant non authentifié peut exploiter la faille sans privilège préalable ; selon les fichiers accessibles, cela peut faciliter une compromission plus large (secrets, clés, configuration).\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}]}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"collection\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"coll-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Nous avons deux codes à analyser : le **code de setup** du challenge (engrenage au-dessus de la catégorie Input) et le code exécuté **après chaque requête**.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"coll-bloc-02\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Le setup décrit l\'**architecture de la base** et les chemins des fichiers (`/public/document_alpha.txt`, `super_secret.txt`, etc.). Une requête sans paramètre renvoie une page HTML listant les actions **sign** et **download**.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"coll-bloc-03\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Flux nominal sur un fichier public : `action=sign` + `filename=public/document_alpha.txt`, puis `action=download` avec `expires` et `signature`. Le contenu renvoyé confirme l\'accès au répertoire `/public`.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"coll-bloc-04\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Une tentative de signature sur `super_secret.txt` échoue : *« Accès refusé. La signature est réservée au préfixe public/ »*. La fonction `generatePresignedUrl()` impose le préfixe `/public` et rejette `..` **avant** assainissement, mais ne revérifie pas après `sanitizeFilename()`.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}]}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"description\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"scope\\\\\\\": \\\\\\\"U\\\\\\\", \\\\\\\"integrity\\\\\\\": \\\\\\\"N\\\\\\\", \\\\\\\"attackVector\\\\\\\": \\\\\\\"N\\\\\\\", \\\\\\\"availability\\\\\\\": \\\\\\\"N\\\\\\\", \\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"desc-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Le challenge 50, appelé **Bucket Vault**, consiste à récupérer un fichier secret `super_secret.txt` qui contient le flag permettant de valider ce CTF. Ce fichier est gardé dans un système de stockage sécurisé qui utilise des **liens d\'accès temporaires** : des jetons valables une heure et une **signature numérique** vérifiée avant toute livraison.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"desc-bloc-02\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Le stockage est implémenté en **PHP** ; on interagit via des **requêtes GET** et l\'application renvoie une page **HTML** décrivant le résultat (signature, téléchargement, erreurs).\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}], \\\\\\\"confidentiality\\\\\\\": \\\\\\\"H\\\\\\\", \\\\\\\"userInteraction\\\\\\\": \\\\\\\"N\\\\\\\", \\\\\\\"attackComplexity\\\\\\\": \\\\\\\"L\\\\\\\", \\\\\\\"privilegesRequired\\\\\\\": \\\\\\\"N\\\\\\\"}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"remediation\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"remed-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Recontrôler la présence de `..` **après** `sanitizeFilename()` (ou normaliser le chemin avec `realpath` dans un répertoire de confinement). Refuser toute résolution qui sort du préfixe `/public`. Journaliser et limiter les tentatives de traversal.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}]}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"exploitation\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"expl-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"D\'après l\'arborescence, `super_secret.txt` et le dossier `/public` sont à la **racine** du stockage. Pour lire le flag il faut d\'abord obtenir une signature en respectant le préfixe `/public`, puis **remonter d\'un niveau** (`..`) pour sortir du répertoire imposé.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"expl-bloc-02\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"La vulnérabilité : le contrôle `str_contains($filename, \'..\')` s\'applique **avant** `sanitizeFilename()`, qui supprime les caractères de contrôle. En insérant un saut de ligne entre les points (`./\\\\\\\\n.`), la chaîne passe le filtre puis recompose `..` après assainissement.\\\\\\\", \\\\\\\"lists\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"expl-list-01\\\\\\\", \\\\\\\"items\\\\\\\": [\\\\\\\"La première condition échoue car les deux points ne sont pas adjacents.\\\\\\\", \\\\\\\"Après assainissement, `\\\\\\\\n` est retiré et la chaîne devient `..`.\\\\\\\"], \\\\\\\"title\\\\\\\": \\\\\\\"Chaîne d\'exemple : `./\\\\\\\\n.`\\\\\\\", \\\\\\\"ordered\\\\\\\": false, \\\\\\\"titleBold\\\\\\\": false}], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}]}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"proofOfConcept\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"poc-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Obtenir la signature du fichier secret :\\\\\\\", \\\\\\\"lists\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"poc-list-sign\\\\\\\", \\\\\\\"items\\\\\\\": [\\\\\\\"Action : sign\\\\\\\", \\\\\\\"Filename : public/.\\\\\\\\n./super_secret.txt\\\\\\\"], \\\\\\\"title\\\\\\\": \\\\\\\"Requête de signature\\\\\\\", \\\\\\\"ordered\\\\\\\": false, \\\\\\\"titleBold\\\\\\\": false}], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"poc-bloc-02\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Télécharger le fichier avec la signature et la date d\'expiration obtenues :\\\\\\\", \\\\\\\"lists\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"poc-list-dl\\\\\\\", \\\\\\\"items\\\\\\\": [\\\\\\\"Action : download\\\\\\\", \\\\\\\"Filename : public/../super_secret.txt\\\\\\\", \\\\\\\"Expires : <valeur retournée>\\\\\\\", \\\\\\\"Signature : <valeur retournée>\\\\\\\"], \\\\\\\"title\\\\\\\": \\\\\\\"Requête de téléchargement\\\\\\\", \\\\\\\"ordered\\\\\\\": false, \\\\\\\"titleBold\\\\\\\": false}], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}]}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\"}',	'2026-05-17 20:38:34.092',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 20:56:25.336'