rmat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}]}\\\", \\\"attachments\\\": [], \\\"currentRound\\\": 2, \\\"assignedReviewerRole\\\": null}\", \"collection\": \"{\\\"status\\\": \\\"approved\\\", \\\"payload\\\": \\\"{\\\\\\\"sectionBlocs\\\\\\\": [{\\\\\\\"id\\\\\\\": \\\\\\\"coll-bloc-01\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Nous avons deux codes à analyser : le **code de setup** du challenge (engrenage au-dessus de la catégorie Input) et le code exécuté **après chaque requête**.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}}, {\\\\\\\"id\\\\\\\": \\\\\\\"coll-bloc-02\\\\\\\", \\\\\\\"body\\\\\\\": \\\\\\\"Le setup décrit l\'**architecture de la base** et les chemins des fichiers (`/public/document_alpha.txt`, `super_secret.txt`, etc.). Une requête sans paramètre renvoie une page HTML listant les actions **sign** et **download**.\\\\\\\", \\\\\\\"lists\\\\\\\": [], \\\\\\\"heading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"subheading\\\\\\\": \\\\\\\"\\\\\\\", \\\\\\\"attachmentId\\\\\\\": null, \\\\\\\"headingFormat\\\\\\\": {\\\\\\\"color\\\\\\\": \\\\\\\"#1e293b\\\\\\\", \\\\\\\"style\\\\\\\": \\\\\\\"normal\\\\\\\", \\\\\\\"fontSize\\\\\\\": \\\\\\\"medium\\\\\\\"}, \\\\\\\"subheadingFormat\\\\\\\": {\\\\\\\"color