CREATE TABLE `report_draft_steps` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `report_draft_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `step` enum('META','DESCRIPTION','COLLECTION','EXPLOITATION','PROOF_OF_CONCEPT','RISKS','REMEDIATION','FINAL') COLLATE utf8mb4_unicode_ci NOT NULL,
  `payload` json NOT NULL,
  `status` enum('IN_PROGRESS','AWAITING_REVIEW','NEEDS_REVISION','APPROVED','IN_GLOBAL_PROGRESS','NEEDS_GLOBAL_REVISION','AWAITING_GLOBAL_REVIEW') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'IN_PROGRESS',
  `current_round` int NOT NULL DEFAULT '0',
  `assigned_reviewer_role` enum('HUNTER','MENTOR','QUALITY_CHECKER','SUPER_ADMIN') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `report_draft_steps_report_draft_id_step_key` (`report_draft_id`,`step`),
  KEY `report_draft_steps_report_draft_id_idx` (`report_draft_id`),
  CONSTRAINT `report_draft_steps_report_draft_id_fkey` FOREIGN KEY (`report_draft_id`) REFERENCES `report_drafts` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `report_draft_steps` (`id`, `report_draft_id`, `step`, `payload`, `status`, `current_round`, `assigned_reviewer_role`, `created_at`, `updated_at`) VALUES
('0d489d4b-8f96-4efe-8ca2-4492d64e6dee',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'META',	'{\"cve\": \"\", \"impact\": \"\", \"bugType\": \"CWE-77\", \"ipsUsed\": \"\", \"payload\": \"\", \"endpoint\": \"GET /?action=generate&filename=myfilename&signature=\", \"scopeSlug\": \"\", \"reportTitle\": \"New problem\", \"vulnerablePartName\": \"mysecret.txt\", \"technicalEnvironment\": \"\", \"applicationFingerprint\": \"\", \"vulnerablePartCategory\": \"JSON_BODY_FIELD\"}',	'APPROVED',	3,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.776'),
('0eeedb15-ca2a-4a7b-a39c-bfbd49080a05',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'EXPLOITATION',	'{\"sectionBlocs\": [{\"id\": \"55ce3732-7446-47b1-9ab7-8300f254bbbf\", \"body\": \"D’après l’arborescence qu’on à pu déduire, le fichier “super_secret.txt” et le dossier\\n“/public” sont à la racine du stockage.\\n\\nPour accéder au fichier “super_secret.txt” on doit d’abord générer une signature.\\n\\nEn prenant en compte que notre chemin doit obligatoirement commencer par “/public”, nous allons devoir remonter d’un niveau pour revenir à la racine du stockage.​\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"bee69b66-4ea8-4fe4-a1b1-128494adc25b\", \"body\": \"Nous devons donc réussir à faire passer les “..” dans la string finale, c’est à dire la string qui ressort de la fonction sanitizeFilename().\\nLa vulnérabilité ici c’est qu’on ne vérifie pas si la string qui ressort de la fonction sanitizeFilename() contient les “..” On peut donc les séparer d’un caractère pour passer la première condition : if (str_contains($filename, \'..\'))\\n\\nEnsuite, il faut profiter du fait que la fonction sanitizeFilename() supprime des caractères de contrôle pour recoller les deux points.\", \"lists\": [{\"id\": \"19c44682-a694-42e4-85eb-5f6517acc4c0\", \"items\": [\"Elle passe la première condition car les points ne sont pas côte à côte.\", \"lors de son passage dans la fonction sanitizeFilename(), “\\\\n” est supprimé car c’est un caractère de contrôle et on obtient alors “..”.​\"], \"title\": \"Imaginons que nous ayons cette string : “.\\\\n.” :\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	3,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.811'),
('3e9acecc-45d3-4642-992c-966659483f0c',	'd317d860-0e2f-4602-b001-55013cf83425',	'META',	'{\"cve\": \"CVE 2026-09608\", \"impact\": \"\", \"bugType\": \"CWE-352\", \"ipsUsed\": \"203.47.78.9, 678.123.890.56\", \"payload\": \"form_upload.ts\", \"endpoint\": \"GET /?action=generate&filename=myfilename&signature=\", \"scopeSlug\": \"dojo-50\", \"reportTitle\": \"CSRF vulnerability on banco.com\", \"vulnerablePartName\": \"input n°67\", \"technicalEnvironment\": \"\", \"applicationFingerprint\": \"\", \"vulnerablePartCategory\": \"GET_PARAMETER\"}',	'APPROVED',	1,	'QUALITY_CHECKER',	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.108'),
('4a9a8ba3-50cf-4825-ab28-d45daef68699',	'd317d860-0e2f-4602-b001-55013cf83425',	'DESCRIPTION',	'{\"scope\": \"\", \"integrity\": \"\", \"attackVector\": \"\", \"availability\": \"\", \"sectionBlocs\": [{\"id\": \"06998e80-36e1-4e0e-8d95-573dd9e8e503\", \"body\": \"Lorem ipsum dolor sit amet consectetur adipiscing elit. Quisque faucibus ex sapien vitae pellentesque sem placerat. In id cursus mi pretium tellus duis convallis. Tempus leo eu aenean sed diam urna tempor. Pulvinar vivamus fringilla lacus nec metus bibendum egestas. Iaculis massa nisl malesuada lacinia integer nunc. Ut hendrerit semper vel class aptent taciti sociosqu. Ad litora torquent per conubia nostra inceptos himenaeos.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": \"8f0890cc-26ab-4fe5-9211-62bd833f57fa\", \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"d6d5c561-91b0-4d64-a562-185cf6360e67\", \"body\": \"Lorem ipsum dolor sit amet consectetur adipiscing elit. Quisque faucibus ex sapien vitae pellentesque sem. \", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": \"9a0e4671-3a0b-4443-93e7-34e014f6a987\", \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}], \"confidentiality\": \"\", \"userInteraction\": \"\", \"attackComplexity\": \"\", \"privilegesRequired\": \"\"}',	'NEEDS_REVISION',	3,	'QUALITY_CHECKER',	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.115'),
('5a280855-a2e2-4813-900f-14c212ed3022',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'DESCRIPTION',	'{\"availability\": \"H\"}',	'APPROVED',	2,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.788'),
('797c1ffc-689c-4e64-8122-177412559c5a',	'd317d860-0e2f-4602-b001-55013cf83425',	'PROOF_OF_CONCEPT',	'{}',	'IN_PROGRESS',	0,	NULL,	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.138'),
('799f1873-2013-48df-901d-58f880986486',	'd317d860-0e2f-4602-b001-55013cf83425',	'FINAL',	'{}',	'IN_PROGRESS',	0,	NULL,	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.158'),
('7e10c953-fdf5-414d-9eea-d8feeaf48620',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'PROOF_OF_CONCEPT',	'{\"sectionBlocs\": [{\"id\": \"8d945659-2bc0-4ce9-98c3-bf99d9c5418c\", \"body\": \"\", \"lists\": [{\"id\": \"329f06c0-6f80-4f59-8dea-ef047c31d685\", \"items\": [\"Action : sign\", \"Filename : public/. ./super_secret.txt\"], \"title\": \"Pour obtenir la signature du fichier “super_secret.txt” :\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.827'),
('7fc5cbe6-2244-4062-b5f9-bbeecf47a673',	'd317d860-0e2f-4602-b001-55013cf83425',	'COLLECTION',	'{}',	'IN_PROGRESS',	0,	NULL,	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.125'),
('9d4164cf-d305-4df9-87fe-7b5254c33662',	'd317d860-0e2f-4602-b001-55013cf83425',	'EXPLOITATION',	'{}',	'IN_PROGRESS',	0,	NULL,	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.130'),
('9da3c39d-7657-42a6-8d73-8748ae5a933d',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'REMEDIATION',	'{\"sectionBlocs\": [{\"id\": \"4810913e-cca1-4050-acb0-7a3965ac2250\", \"body\": \"Ajouter une vérification après l’assainissement du chemin par la fonction sanitizeFilename() semble pertinent. En effet, si la condition de la présence des “..” était présente à la ce niveau, l’exploitation n’aurait pas fonctionnée\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.848'),
('a18162c7-3bcc-4cf1-8216-f060b6a2c301',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'FINAL',	'{\"sectionBlocs\": []}',	'APPROVED',	2,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.856'),
('a516127a-1cf1-4b37-92af-b56a56aeab92',	'd317d860-0e2f-4602-b001-55013cf83425',	'RISKS',	'{}',	'IN_PROGRESS',	0,	NULL,	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.146'),
('bbbbbbbb-0010-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'META',	'{\"cve\": \"\", \"impact\": \"Lecture de fichier arbitraire et fuite de données (flag CTF)\", \"bugType\": \"CWE-22\", \"ipsUsed\": \"\", \"payload\": \"public/.\\n./super_secret.txt\", \"endpoint\": \"GET /?action=generate&filename=...&expires=...&signature=...\", \"scopeSlug\": \"dojo-50\", \"reportTitle\": \"Rapport challenge n°50 Dojo YesWeHack\", \"vulnerablePartName\": \"filename\", \"technicalEnvironment\": \"Dojo YesWeHack — PHP, stockage signé\", \"applicationFingerprint\": \"PHP — Bucket Vault\", \"vulnerablePartCategory\": \"GET_PARAMETER\"}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0011-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'DESCRIPTION',	'{\"scope\": \"U\", \"integrity\": \"N\", \"attackVector\": \"N\", \"availability\": \"N\", \"sectionBlocs\": [{\"id\": \"desc-bloc-01\", \"body\": \"Le challenge 50, appelé **Bucket Vault**, consiste à récupérer un fichier secret `super_secret.txt` qui contient le flag permettant de valider ce CTF. Ce fichier est gardé dans un système de stockage sécurisé qui utilise des **liens d\'accès temporaires** : des jetons valables une heure et une **signature numérique** vérifiée avant toute livraison.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"desc-bloc-02\", \"body\": \"Le stockage est implémenté en **PHP** ; on interagit via des **requêtes GET** et l\'application renvoie une page **HTML** décrivant le résultat (signature, téléchargement, erreurs).\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}], \"confidentiality\": \"H\", \"userInteraction\": \"N\", \"attackComplexity\": \"L\", \"privilegesRequired\": \"N\"}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0012-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'COLLECTION',	'{\"sectionBlocs\": [{\"id\": \"coll-bloc-01\", \"body\": \"Nous avons deux codes à analyser : le **code de setup** du challenge (engrenage au-dessus de la catégorie Input) et le code exécuté **après chaque requête**.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"coll-bloc-02\", \"body\": \"Le setup décrit l\'**architecture de la base** et les chemins des fichiers (`/public/document_alpha.txt`, `super_secret.txt`, etc.). Une requête sans paramètre renvoie une page HTML listant les actions **sign** et **download**.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"coll-bloc-03\", \"body\": \"Flux nominal sur un fichier public : `action=sign` + `filename=public/document_alpha.txt`, puis `action=download` avec `expires` et `signature`. Le contenu renvoyé confirme l\'accès au répertoire `/public`.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"coll-bloc-04\", \"body\": \"Une tentative de signature sur `super_secret.txt` échoue : *« Accès refusé. La signature est réservée au préfixe public/ »*. La fonction `generatePresignedUrl()` impose le préfixe `/public` et rejette `..` **avant** assainissement, mais ne revérifie pas après `sanitizeFilename()`.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0013-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'EXPLOITATION',	'{\"sectionBlocs\": [{\"id\": \"expl-bloc-01\", \"body\": \"D\'après l\'arborescence, `super_secret.txt` et le dossier `/public` sont à la **racine** du stockage. Pour lire le flag il faut d\'abord obtenir une signature en respectant le préfixe `/public`, puis **remonter d\'un niveau** (`..`) pour sortir du répertoire imposé.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"expl-bloc-02\", \"body\": \"La vulnérabilité : le contrôle `str_contains($filename, \'..\')` s\'applique **avant** `sanitizeFilename()`, qui supprime les caractères de contrôle. En insérant un saut de ligne entre les points (`./\\n.`), la chaîne passe le filtre puis recompose `..` après assainissement.\", \"lists\": [{\"id\": \"expl-list-01\", \"items\": [\"La première condition échoue car les deux points ne sont pas adjacents.\", \"Après assainissement, `\\n` est retiré et la chaîne devient `..`.\"], \"title\": \"Chaîne d\'exemple : `./\\n.`\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0014-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'PROOF_OF_CONCEPT',	'{\"sectionBlocs\": [{\"id\": \"poc-bloc-01\", \"body\": \"Obtenir la signature du fichier secret :\", \"lists\": [{\"id\": \"poc-list-sign\", \"items\": [\"Action : sign\", \"Filename : public/.\\n./super_secret.txt\"], \"title\": \"Requête de signature\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"poc-bloc-02\", \"body\": \"Télécharger le fichier avec la signature et la date d\'expiration obtenues :\", \"lists\": [{\"id\": \"poc-list-dl\", \"items\": [\"Action : download\", \"Filename : public/../super_secret.txt\", \"Expires : <valeur retournée>\", \"Signature : <valeur retournée>\"], \"title\": \"Requête de téléchargement\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0015-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'RISKS',	'{\"sectionBlocs\": [{\"id\": \"risk-bloc-01\", \"body\": \"Le risque principal est la **lecture de fichier arbitraire** hors du répertoire autorisé, entraînant une fuite de données sensibles (ici le flag). Un attaquant non authentifié peut exploiter la faille sans privilège préalable ; selon les fichiers accessibles, cela peut faciliter une compromission plus large (secrets, clés, configuration).\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0016-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'REMEDIATION',	'{\"sectionBlocs\": [{\"id\": \"remed-bloc-01\", \"body\": \"Recontrôler la présence de `..` **après** `sanitizeFilename()` (ou normaliser le chemin avec `realpath` dans un répertoire de confinement). Refuser toute résolution qui sort du préfixe `/public`. Journaliser et limiter les tentatives de traversal.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('bbbbbbbb-0017-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'FINAL',	'{\"sectionBlocs\": []}',	'APPROVED',	2,	NULL,	'2026-05-17 13:26:15.306',	'2026-05-17 21:08:25.731'),
('c270ea83-ec8a-4482-9842-6dc03a1321c0',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'RISKS',	'{\"sectionBlocs\": [{\"id\": \"622119bb-7506-48c9-a37c-82c1d93fbfd3\", \"body\": \"Le risque associé à cette vulnérabilité est la lecture de fichier arbitraire qui entraîne une fuite de données. N’importe quel individu peut s’extraire du répertoire imposé (ici /public) ce qui peut mener à l’accès de données sensibles. En fonction des informations fuitées, un attaquant peut s’infiltrer sur le serveur, sur des comptes, réaliser une élévation de privilège, s’il obtient par exemple des identifiants écrits dans ces fichiers privés.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.840'),
('de70bb5d-4690-4d90-b095-76fc13659d03',	'd317d860-0e2f-4602-b001-55013cf83425',	'REMEDIATION',	'{}',	'IN_PROGRESS',	0,	NULL,	'2026-05-20 08:37:39.499',	'2026-05-22 10:36:55.152'),
('ef534dc8-0a2e-45a5-a6f2-40b0d5191c3d',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'COLLECTION',	'{\"sectionBlocs\": [{\"id\": \"0dca10ae-304b-4f51-88e0-57261d6ae25a\", \"body\": \"Nous avons deux codes à analyser : tout d’abord le code de setup du challenge.\\nOn obtient ce code en appuyant sur l’engrenage en haut à gauche, situé au dessus de la\\ncatégorie Input :\", \"lists\": [{\"id\": \"a5c44202-3835-4463-ac7b-934fe0ccbfdd\", \"items\": [\"\"], \"title\": \"\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"d6510cfb-a800-4cbb-8fd5-1264c3585a93\", \"body\": \"Ce code contient les instructions pour peupler la base données sécurisée qui contient les\\nfichiers dont le fichier “super_secret.txt”. Il y a également l’HTML qui va nous être renvoyé à\\nla suite de nos requêtes.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"1d0a7344-c1a4-4768-985e-a5dcae1037ce\", \"body\": \"On peut déjà obtenir des informations notables : l’architecture de la base de données et\\nles noms complets des fichiers qui si trouvent :\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'APPROVED',	2,	'QUALITY_CHECKER',	'2026-05-16 08:23:44.959',	'2026-05-22 10:43:41.799');

CREATE TABLE `report_draft_teams` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
