  `label` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `report_draft_teams_report_draft_id_key` (`report_draft_id`),
  KEY `report_draft_teams_report_draft_id_idx` (`report_draft_id`),
  CONSTRAINT `report_draft_teams_report_draft_id_fkey` FOREIGN KEY (`report_draft_id`) REFERENCES `report_drafts` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

