CREATE TABLE `submission_content_snapshots` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submission_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `payload` json NOT NULL,
  `captured_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  KEY `submission_content_snapshots_submission_id_idx` (`submission_id`),
  CONSTRAINT `submission_content_snapshots_submission_id_fkey` FOREIGN KEY (`submission_id`) REFERENCES `submissions` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `submissions` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `report_draft_step_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `report_draft_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `step` enum('META','DESCRIPTION','COLLECTION','EXPLOITATION','PROOF_OF_CONCEPT','RISKS','REMEDIATION','FINAL') COLLATE utf8mb4_unicode_ci NOT NULL,
  `round` int NOT NULL,
  `submission_kind` enum('HUNTER_TO_REVIEWER','HUNTER_TO_MENTOR','MENTOR_TO_QC','QC_TO_MENTOR','QC_TO_SUPER_ADMIN') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'HUNTER_TO_REVIEWER',
  `payload` json NOT NULL,
  `submitted_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `submitted_by` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reviewer_role` enum('HUNTER','MENTOR','QUALITY_CHECKER','SUPER_ADMIN') COLLATE utf8mb4_unicode_ci NOT NULL,
  `decision` enum('PENDING','APPROVE','REQUEST_CHANGES','ENDORSE') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING',
  `decided_at` datetime(3) DEFAULT NULL,
  `decided_by` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `submissions_report_draft_step_id_round_reviewer_role_submiss_key` (`report_draft_step_id`,`round`,`reviewer_role`,`submission_kind`),
  KEY `submissions_report_draft_id_idx` (`report_draft_id`),
  KEY `submissions_reviewer_role_decision_idx` (`reviewer_role`,`decision`),
  CONSTRAINT `submissions_report_draft_id_fkey` FOREIGN KEY (`report_draft_id`) REFERENCES `report_drafts` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `submissions_report_draft_step_id_fkey` FOREIGN KEY (`report_draft_step_id`) REFERENCES `report_draft_steps` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

