('8b6abe69-ac17-4bc2-80d4-d35488615b96',	'ef534dc8-0a2e-45a5-a6f2-40b0d5191c3d',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'COLLECTION',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"0dca10ae-304b-4f51-88e0-57261d6ae25a\", \"body\": \"Nous avons deux codes à analyser : tout d’abord le code de setup du challenge.\\nOn obtient ce code en appuyant sur l’engrenage en haut à gauche, situé au dessus de la\\ncatégorie Input :\", \"lists\": [{\"id\": \"a5c44202-3835-4463-ac7b-934fe0ccbfdd\", \"items\": [\"\"], \"title\": \"\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"d6510cfb-a800-4cbb-8fd5-1264c3585a93\", \"body\": \"Ce code contient les instructions pour peupler la base données sécurisée qui contient les\\nfichiers dont le fichier “super_secret.txt”. Il y a également l’HTML qui va nous être renvoyé à\\nla suite de nos requêtes.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"1d0a7344-c1a4-4768-985e-a5dcae1037ce\", \"body\": \"On peut déjà obtenir des informations notables : l’architecture de la base de données et\\nles noms complets des fichiers qui si trouvent :\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 08:45:25.844',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 09:00:41.881',	'7f47d