('af7ec7b4-2500-43f4-bb14-37bf79bc8d5f',	'0eeedb15-ca2a-4a7b-a39c-bfbd49080a05',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'EXPLOITATION',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"55ce3732-7446-47b1-9ab7-8300f254bbbf\", \"body\": \"D’après l’arborescence qu’on à pu déduire, le fichier “super_secret.txt” et le dossier\\n“/public” sont à la racine du stockage.\\n\\nPour accéder au fichier “super_secret.txt” on doit d’abord générer une signature.\\n\\nEn prenant en compte que notre chemin doit obligatoirement commencer par “/public”, nous allons devoir remonter d’un niveau pour revenir à la racine du stockage.​\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"bee69b66-4ea8-4fe4-a1b1-128494adc25b\", \"body\": \"Nous devons donc réussir à faire passer les “..” dans la string finale, c’est à dire la string qui ressort de la fonction sanitizeFilename().\\nLa vulnérabilité ici c’est qu’on ne vérifie pas si la string qui ressort de la fonction sanitizeFilename() contient les “..” On peut donc les séparer d’un caractère pour passer la première condition : if (str_contains($filename, \'..\'))\\n\\nEnsuite, il faut profiter du fait que la fonction sanitizeFilename() supprime des caractères de contrôle pour recoller les deux points.\", \"lists\": [{\"id\": \"19c44682-a694-42e4-85eb-5f6517acc4c0\", \"items\": [\"Elle passe la première condition car les points ne sont pas côte à côte.\", \"lors de son passage dans la fonction sanitizeFilename(), “\\\\n” est supprimé car c’est un caractère de contrôle et on obtient alors “..”.​\"], \"title\": \"Imaginons que nous ayons cette string : “.\\\\n.” :\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 09:07:50.366',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'REQUEST_CHANGES',	'2026-05-17 09:09:47.407',	'7f47dac6-26d7-480b-bc71-d8c344726e85'),
('b08b034a-5b54-4202-9d68-78426d08af3d',	'ef534dc8-0a2e-45a5-a6f2-40b0d5191c3d',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'COLLECTION',	2,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"0dca10ae-304b-4f51-88e0-57261d6ae25a\", \"body\": \"Nous avons deux codes à analyser : tout d’abord le code de setup du challenge.\\nOn obtient ce code en appuyant sur l’engrenage en haut à gauche, situé au dessus de la\\ncatégorie Input :\", \"lists\": [{\"id\": \"a5c44202-3835-4463-ac7b-934fe0ccbfdd\", \"items\": [\"\"], \"title\": \"\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"d6510cfb-a800-4cbb-8fd5-1264c3585a93\", \"body\": \"Ce code contient les instructions pour peupler la base données sécurisée qui contient les\\nfichiers dont le fichier “super_secret.txt”. Il y a également l’HTML qui va nous être renvoyé à\\nla suite de nos requêtes.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"1d0a7344-c1a4-4768-985e-a5dcae1037ce\", \"body\": \"On peut déjà obtenir des informations notables : l’architecture de la base de données et\\nles noms complets des fichiers qui si trouvent :\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 16:36:44.880',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 16:37:25.389',	'7f47dac6-26d7-480b-bc71-d8c344726e85'),
('bbbbbbbb-0201-4000-8000-000000000001',	'bbbbbbbb-0010-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'META',	1,	'HUNTER_TO_REVIEWER',	'{\"cve\": \"\", \"impact\": \"Lecture de fichier arbitraire et fuite de données (flag CTF)\", \"bugType\": \"CWE-22\", \"ipsUsed\": \"\", \"payload\": \"public/.\\n./super_secret.txt\", \"endpoint\": \"GET /?action=generate&filename=...&expires=...&signature=...\", \"scopeSlug\": \"dojo-50\", \"reportTitle\": \"Rapport challenge n°50 Dojo YesWeHack\", \"vulnerablePartName\": \"filename\", \"technicalEnvironment\": \"Dojo YesWeHack — PHP, stockage signé\", \"applicationFingerprint\": \"PHP — Bucket Vault\", \"vulnerablePartCategory\": \"GET_PARAMETER\"}',	'2026-05-17 13:29:16.038',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 18:25:16.990',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0202-4000-8000-000000000001',	'bbbbbbbb-0011-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'DESCRIPTION',	1,	'HUNTER_TO_REVIEWER',	'{\"scope\": \"U\", \"integrity\": \"N\", \"attackVector\": \"N\", \"availability\": \"N\", \"sectionBlocs\": [{\"id\": \"desc-bloc-01\", \"body\": \"Le challenge 50, appelé **Bucket Vault**, consiste à récupérer un fichier secret `super_secret.txt` qui contient le flag permettant de valider ce CTF. Ce fichier est gardé dans un système de stockage sécurisé qui utilise des **liens d\'accès temporaires** : des jetons valables une heure et une **signature numérique** vérifiée avant toute livraison.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"desc-bloc-02\", \"body\": \"Le stockage est implémenté en **PHP** ; on interagit via des **requêtes GET** et l\'application renvoie une page **HTML** décrivant le résultat (signature, téléchargement, erreurs).\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}], \"confidentiality\": \"H\", \"userInteraction\": \"N\", \"attackComplexity\": \"L\", \"privilegesRequired\": \"N\"}',	'2026-05-17 13:29:16.038',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 18:25:16.990',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0203-4000-8000-000000000001',	'bbbbbbbb-0012-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'COLLECTION',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"coll-bloc-01\", \"body\": \"Nous avons deux codes à analyser : le **code de setup** du challenge (engrenage au-dessus de la catégorie Input) et le code exécuté **après chaque requête**.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"coll-bloc-02\", \"body\": \"Le setup décrit l\'**architecture de la base** et les chemins des fichiers (`/public/document_alpha.txt`, `super_secret.txt`, etc.). Une requête sans paramètre renvoie une page HTML listant les actions **sign** et **download**.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"coll-bloc-03\", \"body\": \"Flux nominal sur un fichier public : `action=sign` + `filename=public/document_alpha.txt`, puis `action=download` avec `expires` et `signature`. Le contenu renvoyé confirme l\'accès au répertoire `/public`.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"coll-bloc-04\", \"body\": \"Une tentative de signature sur `super_secret.txt` échoue : *« Accès refusé. La signature est réservée au préfixe public/ »*. La fonction `generatePresignedUrl()` impose le préfixe `/public` et rejette `..` **avant** assainissement, mais ne revérifie pas après `sanitizeFilename()`.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 18:25:16.990',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 18:26:26.281',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0204-4000-8000-000000000001',	'bbbbbbbb-0013-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'EXPLOITATION',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"expl-bloc-01\", \"body\": \"D\'après l\'arborescence, `super_secret.txt` et le dossier `/public` sont à la **racine** du stockage. Pour lire le flag il faut d\'abord obtenir une signature en respectant le préfixe `/public`, puis **remonter d\'un niveau** (`..`) pour sortir du répertoire imposé.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"expl-bloc-02\", \"body\": \"La vulnérabilité : le contrôle `str_contains($filename, \'..\')` s\'applique **avant** `sanitizeFilename()`, qui supprime les caractères de contrôle. En insérant un saut de ligne entre les points (`./\\n.`), la chaîne passe le filtre puis recompose `..` après assainissement.\", \"lists\": [{\"id\": \"expl-list-01\", \"items\": [\"La première condition échoue car les deux points ne sont pas adjacents.\", \"Après assainissement, `\\n` est retiré et la chaîne devient `..`.\"], \"title\": \"Chaîne d\'exemple : `./\\n.`\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 18:25:16.990',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'REQUEST_CHANGES',	'2026-05-17 18:26:26.281',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0205-4000-8000-000000000001',	'bbbbbbbb-0013-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'EXPLOITATION',	2,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"expl-bloc-01\", \"body\": \"D\'après l\'arborescence, `super_secret.txt` et le dossier `/public` sont à la **racine** du stockage. Pour lire le flag il faut d\'abord obtenir une signature en respectant le préfixe `/public`, puis **remonter d\'un niveau** (`..`) pour sortir du répertoire imposé.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"expl-bloc-02\", \"body\": \"La vulnérabilité : le contrôle `str_contains($filename, \'..\')` s\'applique **avant** `sanitizeFilename()`, qui supprime les caractères de contrôle. En insérant un saut de ligne entre les points (`./\\n.`), la chaîne passe le filtre puis recompose `..` après assainissement.\", \"lists\": [{\"id\": \"expl-list-01\", \"items\": [\"La première condition échoue car les deux points ne sont pas adjacents.\", \"Après assainissement, `\\n` est retiré et la chaîne devient `..`.\"], \"title\": \"Chaîne d\'exemple : `./\\n.`\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 18:26:26.281',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 20:38:34.092',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0206-4000-8000-000000000001',	'bbbbbbbb-0014-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'PROOF_OF_CONCEPT',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"poc-bloc-01\", \"body\": \"Obtenir la signature du fichier secret :\", \"lists\": [{\"id\": \"poc-list-sign\", \"items\": [\"Action : sign\", \"Filename : public/.\\n./super_secret.txt\"], \"title\": \"Requête de signature\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"poc-bloc-02\", \"body\": \"Télécharger le fichier avec la signature et la date d\'expiration obtenues :\", \"lists\": [{\"id\": \"poc-list-dl\", \"items\": [\"Action : download\", \"Filename : public/../super_secret.txt\", \"Expires : <valeur retournée>\", \"Signature : <valeur retournée>\"], \"title\": \"Requête de téléchargement\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 18:26:26.281',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 20:38:34.092',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0207-4000-8000-000000000001',	'bbbbbbbb-0015-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'RISKS',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"risk-bloc-01\", \"body\": \"Le risque principal est la **lecture de fichier arbitraire** hors du répertoire autorisé, entraînant une fuite de données sensibles (ici le flag). Un attaquant non authentifié peut exploiter la faille sans privilège préalable ; selon les fichiers accessibles, cela peut faciliter une compromission plus large (secrets, clés, configuration).\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 18:26:26.281',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 20:38:34.092',	'cccccccc-0020-4000-8000-000000000001'),
('bbbbbbbb-0208-4000-8000-000000000001',	'bbbbbbbb-0016-4000-8000-000000000001',	'bbbbbbbb-0001-4000-8000-000000000001',	'REMEDIATION',	1,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"remed-bloc-01\", \"body\": \"Recontrôler la présence de `..` **après** `sanitizeFilename()` (ou normaliser le chemin avec `realpath` dans un répertoire de confinement). Refuser toute résolution qui sort du préfixe `/public`. Journaliser et limiter les tentatives de traversal.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 18:26:26.281',	'cccccccc-0010-4000-8000-000000000001',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 20:38:34.092',	'cccccccc-0020-4000-8000-000000000001'),
