('cf8e10c1-9b2a-4ad3-93e4-9c4768f11ca5',	'4a9a8ba3-50cf-4825-ab28-d45daef68699',	'd317d860-0e2f-4602-b001-55013cf83425',	'DESCRIPTION',	1,	'HUNTER_TO_REVIEWER',	'{\"scope\": \"\", \"integrity\": \"\", \"attackVector\": \"\", \"availability\": \"\", \"sectionBlocs\": [{\"id\": \"06998e80-36e1-4e0e-8d95-573dd9e8e503\", \"body\": \"Lorem ipsum dolor sit amet consectetur adipiscing elit. Quisque faucibus ex sapien vitae pellentesque sem placerat. In id cursus mi pretium tellus duis convallis. Tempus leo eu aenean sed diam urna tempor. Pulvinar vivamus fringilla lacus nec metus bibendum egestas. Iaculis massa nisl malesuada lacinia integer nunc posuere. Ut hendrerit semper vel class aptent taciti sociosqu. Ad litora torquent per conubia nostra inceptos himenaeos.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": \"8f0890cc-26ab-4fe5-9211-62bd833f57fa\", \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"d6d5c561-91b0-4d64-a562-185cf6360e67\", \"body\": \"Lorem ipsum dolor sit amet consectetur adipiscing elit. Quisque faucibus ex sapien vitae pellentesque sem placerat. \", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": \"9a0e4671-3a0b-4443-93e7-34e014f6a987\", \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}], \"confidentiality\": \"\", \"userInteraction\": \"\", \"attackComplexity\": \"\", \"privilegesRequired\": \"\"}',	'2026-05-20 12:40:46.207',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'REQUEST_CHANGES',	'2026-05-20 21:45:40.279',	'7f47dac6-26d7-480b-bc71-d8c344726e85'),
('d4565f7b-0ab6-42f1-889c-3ec221a1f931',	'5a280855-a2e2-4813-900f-14c212ed3022',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'DESCRIPTION',	2,	'HUNTER_TO_REVIEWER',	'{\"availability\": \"H\"}',	'2026-05-17 16:32:43.459',	'demo-user',	'SUPER_ADMIN',	'PENDING',	NULL,	NULL),
('e65aa1b4-6109-42d5-92dc-a1f912a67a99',	'9da3c39d-7657-42a6-8d73-8748ae5a933d',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'REMEDIATION',	2,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"4810913e-cca1-4050-acb0-7a3965ac2250\", \"body\": \"Ajouter une vérification après l’assainissement du chemin par la fonction sanitizeFilename() semble pertinent. En effet, si la condition de la présence des “..” était présente à la ce niveau, l’exploitation n’aurait pas fonctionnée\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 16:36:35.293',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 16:37:05.990',	'7f47dac6-26d7-480b-bc71-d8c344726e85'),
('eae36481-c807-4fec-8dc3-c1a4c32bc73c',	'c270ea83-ec8a-4482-9842-6dc03a1321c0',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'RISKS',	2,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"622119bb-7506-48c9-a37c-82c1d93fbfd3\", \"body\": \"Le risque associé à cette vulnérabilité est la lecture de fichier arbitraire qui entraîne une fuite de données. N’importe quel individu peut s’extraire du répertoire imposé (ici /public) ce qui peut mener à l’accès de données sensibles. En fonction des informations fuitées, un attaquant peut s’infiltrer sur le serveur, sur des comptes, réaliser une élévation de privilège, s’il obtient par exemple des identifiants écrits dans ces fichiers privés.\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 16:36:37.612',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 16:37:16.824',	'7f47dac6-26d7-480b-bc71-d8c344726e85'),
('fb71f1e9-d466-442c-b874-c0b41c0dbb4a',	'0eeedb15-ca2a-4a7b-a39c-bfbd49080a05',	'85e847ba-f59a-4a55-aec7-a51a73a46cae',	'EXPLOITATION',	2,	'HUNTER_TO_REVIEWER',	'{\"sectionBlocs\": [{\"id\": \"55ce3732-7446-47b1-9ab7-8300f254bbbf\", \"body\": \"D’après l’arborescence qu’on à pu déduire, le fichier “super_secret.txt” et le dossier\\n“/public” sont à la racine du stockage.\\n\\nPour accéder au fichier “super_secret.txt” on doit d’abord générer une signature.\\n\\nEn prenant en compte que notre chemin doit obligatoirement commencer par “/public”, nous allons devoir remonter d’un niveau pour revenir à la racine du stockage.​\", \"lists\": [], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}, {\"id\": \"bee69b66-4ea8-4fe4-a1b1-128494adc25b\", \"body\": \"Nous devons donc réussir à faire passer les “..” dans la string finale, c’est à dire la string qui ressort de la fonction sanitizeFilename().\\nLa vulnérabilité ici c’est qu’on ne vérifie pas si la string qui ressort de la fonction sanitizeFilename() contient les “..” On peut donc les séparer d’un caractère pour passer la première condition : if (str_contains($filename, \'..\'))\\n\\nEnsuite, il faut profiter du fait que la fonction sanitizeFilename() supprime des caractères de contrôle pour recoller les deux points.\", \"lists\": [{\"id\": \"19c44682-a694-42e4-85eb-5f6517acc4c0\", \"items\": [\"Elle passe la première condition car les points ne sont pas côte à côte.\", \"lors de son passage dans la fonction sanitizeFilename(), “\\\\n” est supprimé car c’est un caractère de contrôle et on obtient alors “..”.​\"], \"title\": \"Imaginons que nous ayons cette string : “.\\\\n.” :\", \"ordered\": false, \"titleBold\": false}], \"heading\": \"\", \"subheading\": \"\", \"attachmentId\": null, \"headingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}, \"subheadingFormat\": {\"color\": \"#1e293b\", \"style\": \"normal\", \"fontSize\": \"medium\"}}]}',	'2026-05-17 16:19:41.714',	'f3b8d208-95d1-41eb-aa4b-02e1ac800dde',	'QUALITY_CHECKER',	'APPROVE',	'2026-05-17 16:20:01.214',	'7f47dac6-26d7-480b-bc71-d8c344726e85');

CREATE TABLE `two_factor` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `method` enum('APP') COLLATE utf8mb4_unicode_ci NOT NULL,
  `verified` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `two_factor_user_id_method_key` (`user_id`,`method`),
  KEY `two_factor_user_id_idx` (`user_id`),
  CONSTRAINT `two_factor_user_id_fkey` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `two_factor_totp` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `two_factor_id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `secret` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `two_factor_totp_two_factor_id_key` (`two_factor_id`),
  CONSTRAINT `two_factor_totp_two_factor_id_fkey` FOREIGN KEY (`two_factor_id`) REFERENCES `two_factor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `users` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `username` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `password_hash` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `two_factor_enabled` bigint NOT NULL DEFAULT '0',
  `role_id` int DEFAULT NULL,
  `is_fake_user` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `users_email_key` (`email`),
  KEY `users_role_id_idx` (`role_id`),
  CONSTRAINT `users_role_id_fkey` FOREIGN KEY (`role_id`) REFERENCES `roles` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

